import React, { useState } from "react";
import "./Signup.css";
import { Button } from "../button/Button";

export const Form = () => {
  const [data, setData] = useState([]);

  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmpassword, setConfirmPassword] = useState("");

  const handleChangeName = (e) => {
    setName(e.target.value);
  };

  const handleChangeEmail = (e) => {
    setEmail(e.target.value);
  };

  const handleChangePassword = (e) => {
    setPassword(e.target.value);
  };

  const handleChangeConfirmPassword = (e) => {
    setConfirmPassword(e.target.value);
  };

  const handleSignup = (e) => {
    e.preventDefault();

    const newData = {
      name: name,
      email: email,
      password: password,
      confirmpassword: confirmpassword,
    };

    if (name && email && password && confirmpassword) {
      setData([newData]);
    } else {
      alert("Please fill all the fields");
    }

    setName("");
    setEmail("");
    setPassword("");
    setConfirmPassword("");
  };

  return (
    <div id="container">
      <form id="form">
        <h2>Create account</h2>

        <label>What is your name?</label>
        <input
          type="text"
          onChange={handleChangeName}
          value={name}
          placeholder="name"
        />

        <label>What is your email?</label>
        <input
          type="number"
          onChange={handleChangeEmail}
          value={email}
          placeholder="email"
        />

        <label>What is your password?</label>
        <input
          type="text"
          onChange={handleChangePassword}
          value={password}
          placeholder="password"
        />

        <Button type="signup" onClick={handleSignup}>
          Sign Up
        </Button>

        <div id="data">
          {data.map((personalData, index) => (
            <div key={index}>
              <p>Name: {personalData.name}</p>
              <p>Email: {personalData.email}</p>
              <p>Password: {personalData.password}</p>
              <p>Confirm Password: {personalData.confirmpassword}</p>
            </div>
          ))}
        </div>
      </form>
    </div>
  );
};
